svg.script:
(() => {
  "use strict";
  const svg = document.getElementById("mini-stage");

  // ── mini-sleep 定稿参数(2026-06-12 鹿鹿二轮定稿,常量烘焙,不开放调参)──
  const SLEEP = {
    cycle: 5.6, tilt: 7, tiltBreath: 1, breathAmp: 1,
    zzzX: 52, zzzY: 86, zzzScale: 1, zzzColor: "#8a5a3f",
    mouthInset: 16, mouthWobble: 2, tuftFloat: 1.5
  };
  const TILT_PIVOT = { x: 187, y: 252 };
  // 领带甩动锚 = 领结中心 tie 局部 (33.5,19)(blade wrapper 在 tie 组内,直接用局部坐标)
  const ZZZ_PARTS = [
    { id: "sleep-zzz-small", relX: 0,   relY: 0,   delay: 0,    dx: -5, dy: -10, scale0: 0.62 },
    { id: "sleep-zzz-mid",   relX: -28, relY: -38, delay: 0.23, dx: -7, dy: -13, scale0: 0.68 },
    { id: "sleep-zzz-large", relX: -52, relY: -85, delay: 0.46, dx: -9, dy: -16, scale0: 0.72 }
  ];

  // ── peek 可调参数 ──
  const state = {
    ext: 51.8,        // M 档:25px × 580/280;S 72.5 / L 40.3
    speed: 1,         // 慢放系数(<1 = 慢动作看细节)
    handDelay: 0,     // ms,钉边=与窗口完全同步(鹿鹿三轮:手一直在边缘)
    handDur: 200,     // ms,= host 窗口 200,同曲线同步,爪全程骑边
    handEase: 0,      // 0=easeOutQuad(host 同款) 1=linear
    trailWidth: 1.8,  // 轨迹线宽(鹿鹿四轮:偏细)
    trailOpacity: 0.75,
    trailFade: 0.45,  // s,推到位后轨迹渐隐时长(手不动=不展示)
    tieSwayAmp: 2.5   // 领带下摆甩幅(°,blade wrapper 绕领结点;领结钉死)
  };
  const EASES = [
    { name: "easeOutQuad(host)", fn: (t) => t * (2 - t) },
    { name: "linear", fn: (t) => t }
  ];
  // 推出模拟时间线:贴边 1.2s → 推出 0.2s(host easeOutQuad) → 保持 2s → 缩回 0.2s
  const T_REST = 1.2, T_PUSH = 0.2, T_HOLD = 2.0, T_PULL = 0.2;
  const T_TOTAL = T_REST + T_PUSH + T_HOLD + T_PULL;
  const LOOP_MODE = /[?&]loop=1\b/.test(location.search);
  const HOST_HOLD_PHASE = T_REST + T_PUSH + T_HOLD / 2;
  const EDGE_BASE = 235;
  const hostEase = EASES[0].fn; // 窗口推出/缩回恒用 host 曲线

  // ── 工具 ──
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function fract(v) { return v - Math.floor(v); }
  function easeOutCubic(v) { const t = clamp(v, 0, 1); return 1 - Math.pow(1 - t, 3); }
  function easeBreath(linear) { return (1 - Math.cos(linear * Math.PI * 2)) / 2; }
  function fmt(v) { return String(parseFloat(Number(v).toFixed(2))); }
  function fmtFine(v) { return String(parseFloat(Number(v).toFixed(4))); }
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (node) {
      if (transform) node.setAttribute("transform", transform);
      else node.removeAttribute("transform");
    }
  }
  function applyMouthInset(inset) {
    ["mouth-left", "mouth-right"].forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (!node || !node.getTotalLength) return;
      const length = node.getTotalLength();
      const visibleLength = Math.max(.1, length - inset);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
    });
  }

  // ── peek 时间线:窗口边缘进度 + 手进度(带延迟,各自独立缓动)──
  // 返回 { edgeP, handP } 都是 0..1(0=贴边,1=推出 ext)
  function peekAt(tSec) {
    const freezeControl = document.getElementById("freeze-hold");
    const freeze = !LOOP_MODE || (freezeControl ? freezeControl.checked : false);
    const p = freeze ? HOST_HOLD_PHASE : (tSec % T_TOTAL);
    const handEase = EASES[state.handEase].fn;
    const dly = state.handDelay / 1000, dur = Math.max(.01, state.handDur / 1000);
    let edgeP, handP, pushSince = -1;
    if (p < T_REST) {
      edgeP = 0; handP = 0;
    } else if (p < T_REST + T_PUSH + T_HOLD) {
      const since = p - T_REST;             // 自推出开始的秒数(跨 push+hold 连续计)
      edgeP = hostEase(clamp(since / T_PUSH, 0, 1));
      handP = handEase(clamp((since - dly) / dur, 0, 1));
      pushSince = since;
    } else {
      const since = p - T_REST - T_PUSH - T_HOLD;  // 自缩回开始
      edgeP = 1 - hostEase(clamp(since / T_PULL, 0, 1));
      handP = 1 - handEase(clamp((since - dly) / dur, 0, 1));
    }
    return { edgeP, handP, phase: p, pushSince };
  }

  // ── 每帧 ──
  const zzzLayer = document.getElementById("sleep-zzz-layer");
  let t0 = performance.now();
  function frame(now) {
    const tReal = (now - t0) / 1000;
    const t = tReal * state.speed;

    // ① mini-sleep 定稿循环(逐字驱动,参数=定稿常量)
    const phase = fract(t / SLEEP.cycle);
    const bt = easeBreath(phase);
    const a = SLEEP.breathAmp;
    setT("sleep-body-breath",
      `translate(187 322) translate(0 ${fmtFine(1.6 * a * bt)}) scale(${fmtFine(1 + 0.024 * a * bt)} ${fmtFine(1 - 0.018 * a * bt)}) translate(-187 -322)`);
    const tiltDeg = -(SLEEP.tilt - SLEEP.tiltBreath * bt);
    setT("sleep-head-tilt", `rotate(${fmt(tiltDeg)} ${TILT_PIVOT.x} ${TILT_PIVOT.y})`);
    const fl = Math.sin(2 * Math.PI * phase) * SLEEP.tuftFloat;
    const fr = Math.sin(2 * Math.PI * phase + .9) * SLEEP.tuftFloat;
    setT("left-tuft", `rotate(${fmt(-32 + fl)} 182 49)`);
    setT("right-tuft", `rotate(${fmt(-32 + fr)} 200 50)`);
    // 领带呼吸(鹿鹿三轮定):领结钉死,只有下摆绕领结点甩(滞后 lag=phase+0.08 主线先例);
    // wrapper 在 tie 组内(局部坐标,锚=领结中心 (33.5,19)),外层 sleep-tie-sway 不再驱动,定稿串不碰
    const lag = easeBreath(fract(phase + 0.08));
    setT("sleep-tie-sway", "");
    setT("tie-blade-sway", `rotate(${fmt(state.tieSwayAmp * (lag * 2 - 1))} 33.5 19)`);
    applyMouthInset(SLEEP.mouthInset + SLEEP.mouthWobble * bt);
    for (const part of ZZZ_PARTS) {
      const node = document.getElementById(part.id);
      if (!node) continue;
      const pz = fract(phase - part.delay);
      const appear = easeOutCubic(pz / 0.24);
      const fade = clamp((pz - 0.64) / 0.24, 0, 1);
      const rise = easeOutCubic(pz / 0.9);
      const s = lerp(part.scale0, 1, appear) * SLEEP.zzzScale;
      const x = SLEEP.zzzX + part.relX * SLEEP.zzzScale + part.dx * rise;
      const y = SLEEP.zzzY + part.relY * SLEEP.zzzScale + part.dy * rise;
      node.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)}) scale(${fmt(s)})`);
      node.setAttribute("opacity", fmt(0.9 * appear * (1 - fade)));
    }

    // ② peek:复用 host 推出曲线驱动手部追赶；生产资产不绘制调试边界
    const pk = peekAt(t);
    const { edgeP, handP } = pk;
    const edgeX = EDGE_BASE + state.ext * edgeP;
    const mask = document.getElementById("edge-mask");
    const line = document.getElementById("edge-line");
    const text = document.getElementById("edge-text");
    if (mask) { mask.setAttribute("x", fmt(edgeX)); mask.setAttribute("width", fmt(430 - edgeX + 150)); }
    if (line) { line.setAttribute("x1", fmt(edgeX)); line.setAttribute("x2", fmt(edgeX)); }
    if (text) text.setAttribute("x", fmt(edgeX + 4));
    // 手钉边(鹿鹿三轮:手一直在显示器边缘):随边平移(屏幕 x+ = 母版 y+),爪全程骑边;
    // 形态=mini-sleep 定稿原样(鹿鹿四轮),clip 不动不补偿。纯平移、不转,定稿串不碰。
    const off = state.ext * handP;
    setT("peek-hands-ext", off > .01 ? `translate(0 ${fmt(off)})` : "");

    // ③ 手掌运动轨迹(鹿鹿四轮):手往下推时才出现的细拖尾,手掌同色 #d8a686;
    // 几何=出发位爪头左缘(209)拖到当前爪头左缘(209+off);到位后渐隐;rest/pull 不展示
    const dlyS = state.handDelay / 1000, durS = Math.max(.01, state.handDur / 1000);
    let trailAlpha = 0;
    if (pk.pushSince >= 0 && off > 0.5) {
      const settled = pk.pushSince - dlyS - durS;   // 手到位后经过的秒数
      trailAlpha = settled <= 0 ? 1 : Math.max(0, 1 - settled / Math.max(.01, state.trailFade));
    }
    const trailA = trailAlpha * state.trailOpacity;
    ["trail-up-top", "trail-up-bottom", "trail-down-top", "trail-down-bottom"].forEach((id) => {
      const n = document.getElementById(id);
      if (!n) return;
      n.setAttribute("x1", "209");
      n.setAttribute("x2", fmt(209 + off));
      n.setAttribute("stroke-width", fmt(state.trailWidth));
      n.setAttribute("opacity", fmt(trailA));
    });

    refreshJson();
    requestAnimationFrame(frame);
  }


  function refreshJson() {} // 面板已剥离(导出无 tuner)

  requestAnimationFrame(frame);
  window.__miniSleepPeek = { state };
})();
